UPDATE organizations SET website = 'https://addguests.com/', updated_at = NOW() WHERE slug = 'addguests';
INSERT INTO legal_entities (id, organization_id, legal_name, siren, country, is_primary, created_at, updated_at) SELECT uuid_generate_v4(), o.id, 'Addguests', '948157532', 'France', TRUE, NOW(), NOW() FROM organizations o WHERE o.slug = 'addguests' AND NOT EXISTS (SELECT 1 FROM legal_entities le WHERE le.organization_id = o.id AND le.siren = '948157532');
